package be.schaubroeck.lpb.rkm.rekenmotor.util;

import be.schaubroeck.lpb.rkm.rekenmotor.LoonElement;
import be.schaubroeck.lpb.rkm.rekenmotor.comparator.LoonElementMetRegimeComparator;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey;
import be.schaubroeck.lpb.rkm.rekenmotor.mapkeys.RekenHoofdArtikelKey;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.enumtypes.AardRekenelement;
import be.schaubroeck.lpb.tools.enumtypes.LnedefRegBv;
import be.schaubroeck.lpb.tools.exception.MessageException;
import be.schaubroeck.temporal.interval.LocalDateInterval;
import com.google.common.collect.Ordering;
import com.google.common.collect.SortedSetMultimap;
import com.google.common.collect.TreeMultimap;

import java.util.Collection;
import java.util.Collections;
import java.util.HashSet;
import java.util.Objects;
import java.util.Set;
import java.util.SortedSet;
import java.util.TreeSet;

public class ArtikelLoonElementManagerImp implements ArtikelLoonElementManager {

    private Set<RekenHoofdArtikelKey> extraRekenHoofdArtikelKeys = new HashSet<>();

    private SortedSetMultimap<RekenHoofdArtikelKey, LoonElement> rekenHoofdArtikelKeyElementen =
            TreeMultimap.create(Ordering.natural(), LoonElementMetRegimeComparator.DEFAULT);

    @Override
    public Collection<LoonElement> getRekenHoofdArtikelElementen(RekenHoofdArtikelKey rekenHoofdArtikelKey) {
        return Collections.unmodifiableSortedSet(rekenHoofdArtikelKeyElementen.get(rekenHoofdArtikelKey));
    }

    @Override
    public Set<RekenHoofdArtikelKey> getRekenHoofdArtikelKeys() {
        Set<RekenHoofdArtikelKey> keys = new TreeSet<>(rekenHoofdArtikelKeyElementen.keySet());
        keys.addAll(extraRekenHoofdArtikelKeys);
        return keys;
    }

    @Override
    public void addExtraRekenHoofdArtikelKey(RekenHoofdArtikelKey key) {
        extraRekenHoofdArtikelKeys.add(key);
    }

    @Override
    public void addLoonElement(LoonElement loonElement, Opper opper, RekenHoofdArtikelKey rekenHoofdArtikelKey) {
        LocalDateInterval rekenLijnPeriode = loonElement.getPropertyUnchecked(RekenChainKey.REKENLIJN_PERIODE_KEY);
        AardRekenelement typeBoeking = loonElement.getPropertyUnchecked(RekenChainKey.REKENLIJN_TYPE_BOEKING_KEY);
        if (getLoonElement(loonElement.getAardKodeExtensie(), opper, rekenHoofdArtikelKey, rekenLijnPeriode, typeBoeking,
                loonElement.getReferentieJaar(), loonElement.getRegimeBv()) == null) {
            loonElement.setOpper(opper);
            rekenHoofdArtikelKeyElementen.put(rekenHoofdArtikelKey, loonElement);
        } else {
            throw new MessageException("Kan loonelement niet toevoegen,de aardKodeExtensie moet uniek zijn per artikel-opper.");
        }
    }

    @Override
    public LoonElement getLoonElement(
            AardKodeExtensie looncode, Opper opper, RekenHoofdArtikelKey rekenHoofdArtikelKey,
            LocalDateInterval rekenLijnPeriode, AardRekenelement typeBoeking, Integer referentieJaar, LnedefRegBv regimeBv) {
        SortedSet<LoonElement> loonElementen = rekenHoofdArtikelKeyElementen.get(rekenHoofdArtikelKey);
        LoonElement found = null;
        for (LoonElement element : loonElementen) {
            LocalDateInterval elementPeriode = element.getPropertyUnchecked(RekenChainKey.REKENLIJN_PERIODE_KEY);
            AardRekenelement elementTypeBoeking = element.getPropertyUnchecked(RekenChainKey.REKENLIJN_TYPE_BOEKING_KEY);
            Integer elemRefJaar = element.getReferentieJaar();

            if (element.getAardKodeExtensie().equals(looncode) && element.getRegimeBv() == regimeBv && element.getOpper().equals(opper) && (
                    (elementTypeBoeking != null && elementTypeBoeking.equals(typeBoeking)) || elementTypeBoeking == typeBoeking) && (
                    (elementPeriode != null && elementPeriode.equals(rekenLijnPeriode)) || elementPeriode == rekenLijnPeriode) && (
                    (elemRefJaar != null && elemRefJaar.equals(referentieJaar)) || Objects.equals(elemRefJaar, referentieJaar))) {
                found = element;
                break;
            }
        }
        return found;
    }

}
